use axum::{
    extract::Query,
    http::{Request, Response},
    routing::get,
    Router,
};
use reqwest::Client;

#[get("/proxy?<url>")]
async fn proxy(url: Query<String>, client: Client) -> Result<Response, reqwest::Error> {
    let url = url.0;
    let res = client.get(url).send().await?;
    Ok(res.into_response())
}

#[tokio::main]
async fn main() {
    let app = Router::new().route("/proxy", get(proxy));
    let client = Client::new();

    axum::Server::bind("0.0.0.0:3000")
        .serve(app.with_data(client).into_make_service())
        .await
        .unwrap();
}